using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval — returns JsonTypeInfo<T> directly, no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// Round-trip to prove it works
var json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");
Person? p = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Deserialized: {p}");

// 2) Probe without throwing — TryGetTypeInfo returns false instead of an exception.
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo(Person): found={found}, type={info?.Type.Name}");

// Probe for a type the resolver knows about (should succeed with DefaultJsonTypeInfoResolver)
bool foundInt = options.TryGetTypeInfo(typeof(int), out JsonTypeInfo? intInfo);
Console.WriteLine($"TryGetTypeInfo(int):    found={foundInt}, type={intInfo?.Type.Name}");

// Probe with a custom resolver that only handles Person — Widget will fail gracefully.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new PersonOnlyResolver())
};

bool hasPerson = limited.TryGetTypeInfo(typeof(Person), out _);
bool hasWidget = limited.TryGetTypeInfo(typeof(Widget), out _);
Console.WriteLine($"\nLimited resolver — Person: {hasPerson}, Widget: {hasWidget}");

// --- Types ---
record Person(string Name, int Age);
record Widget(int Id);

// A resolver that only provides metadata for Person.
sealed class PersonOnlyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return JsonMetadataServices.CreateObjectInfo<Person>(options,
                new JsonObjectInfoValues<Person>
                {
                    ObjectCreator = null,
                    SerializeHandler = (writer, value) =>
                    {
                        writer.WriteStartObject();
                        writer.WriteString("name", value.Name);
                        writer.WriteNumber("age", value.Age);
                        writer.WriteEndObject();
                    }
                });
        return null; // signals "I don't handle this type"
    }
}

